当然，因为我这里是linux环境，所以复现不了 XXE五种解析方式 DOMDOM的全称是Document Object Model，也即文档对象模型。DOM 解析是将一个 XML 文档转换成一个 DOM 树，并将 DOM 树放在内存中。使用大致步骤：
创建一个 DocumentBuilderFactory 对象 创建一个 DocumentBuilder 对象 通过 DocumentBuilder 的 parse() 方法加载 XML 遍历 name 和 value 节点
package com.example.xxedemo;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;import org.w3c.dom.Document;import org.w3c.dom.Node;import org.w3c.dom.NodeList;import org.xml.sax.InputSource;import javax.servlet.http.HttpServletRequest;import javax.xml.parsers.DocumentBuilder;import javax.xml.parsers.DocumentBuilderFactory;import java.io.InputStream;import java.io.StringReader;/** * 编号7089 */@RestControllerpublic class DOMTest &#123; @RequestMapping(&quot;/domdemo/vul&quot;) public String domDemo(HttpServletRequest request) &#123; try &#123;//获取输入流 InputStream in = request.getInputStream(); String body = convertStreamToString(in); StringReader sr = new StringReader(body); InputSource is = new InputSource(sr); DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance(); DocumentBuilder db = dbf.newDocumentBuilder(); Document document = db.parse(is);// 遍历xml节点name和value StringBuilder buf = new StringBuilder(); NodeList rootNodeList = document.getChildNodes(); for (int i = 0; i &lt; rootNodeList.getLength(); i++) &#123; Node rootNode = rootNodeList.item(i); NodeList child = rootNode.getChildNodes(); for (int j = 0; j &lt; child.getLength(); j++) &#123; Node node = child.item(j); buf.append(String.format(&quot;%s: %s\n&quot;, node.getNodeName(), node.getTextContent())); &#125; &#125; sr.close(); return buf.toString(); &#125; catch (Exception e) &#123; return &quot;EXCEPT ERROR!!!&quot;; &#125; &#125; public static String convertStreamToString(java.io.InputStream is) &#123; java.util.Scanner s = new java.util.Scanner(is).useDelimiter(&quot;\\A&quot;); return s.hasNext() ? s.next() : &quot;&quot;; &#125;&#125;
SAXSAX 的全称是 Simple APIs for XML，也即 XML 简单应用程序接口。与 DOM 不同，SAX 提供的访问模式是一种顺序模式，这是一种快速读写 XML 数据的方式。使用大致步骤：
获取 SAXParserFactory 的实例 获取 SAXParser 实例 创建一个 handler() 对象 通过 parser 的 parse() 方法来解析XML
package com.example.xxedemo;import com.sun.org.apache.xml.internal.resolver.readers.SAXParserHandler;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;import org.xml.sax.InputSource;import javax.servlet.http.HttpServletRequest;import javax.xml.parsers.SAXParser;import javax.xml.parsers.SAXParserFactory;import java.io.IOException;import java.io.InputStream;import java.io.StringReader;/** * 编号7089 */@RestControllerpublic class SAXTest &#123; @RequestMapping(&quot;/saxdemo/vul&quot;) public String saxDemo(HttpServletRequest request) throws IOException &#123; //获取输入流 InputStream in = request.getInputStream(); String body = convertStreamToString(in); try &#123; SAXParserFactory spf = SAXParserFactory.newInstance(); SAXParser parser = spf.newSAXParser(); SAXParserHandler handler = new SAXParserHandler();//解析xml parser.parse(new InputSource(new StringReader(body)), handler); return &quot;Sax xxe vuln code&quot;; &#125; catch (Exception e) &#123; return &quot;Error......&quot;; &#125; &#125; public static String convertStreamToString(java.io.InputStream is) &#123; java.util.Scanner s = new java.util.Scanner(is).useDelimiter(&quot;\\A&quot;); return s.hasNext() ? s.next() : &quot;&quot;; &#125;&#125;
JDOMJDOM 是一个开源项目，它基于树型结构，利用纯 JAVA 的技术对 XML 文档实现解析、生成、序列化以及多种操作。使用大致步骤：
创建一个 SAXBuilder 的对象(和上面那个sax不一样) 通过 saxBuilder 的 build() 方法，将输入流加载到 saxBuilder 中 使用 JDOM 需要在 pom.xml 文件中引入该依赖后并重新加载，如下：
&lt;dependency&gt; &lt;groupId&gt;org.jdom&lt;/groupId&gt; &lt;artifactId&gt;jdom&lt;/artifactId&gt; &lt;version&gt;1.1.3&lt;/version&gt;&lt;/dependency&gt;
