URL跳转关键字redirecturlredirectUrlcallbackreturn_urltoUrlReturnUrlfromUrlredUrlrequestredirect_toredirect_urljumpjump_totargettogotolinklinktodomainoauth_callback 301 重定向 - setHeader301跳转也叫301重定向，也叫301转向，也叫301永久重定向,是网站建设过程中的一个功能。一般用于2个域名指向同一个网站。 一般来说，利用跳转，对网站的排名不会有影响。但不会转移全部权重。只能说让损失降到最低。 302 重定向 - sendRedirect302跳转就网址重定向的一种，它区别于301跳转，301是网址永久重定向，302则是网址的临时定向。302转向或者302重定向（302 redirect）指的是当浏览器要求一个网页的时候，主机所返回的状态码。302状态码的意义是暂时转向到另外一个网址。 搜索敏感函数的脚本来自https://github.com/Cryin/JavaID，修改了一部分代码，增加了一些规则，优化了一下输出结果 javaid.py#!/usr/bin/env python3# -*- coding:utf-8 -*-# java source danger function identify prog# Auth by Cryin&#x27;# Modify by This_is_Yimport reimport osimport optparseimport sysfrom lxml.html import etreeimport logging# 写入文件：漏洞类型，具体类型，文件名，匹配到的这行代码，文件路径，# logging.basicConfig(filename=&#x27;example.log&#x27;, encoding=&#x27;utf-8&#x27;, level=logging.DEBUG)logging.basicConfig(level=logging.DEBUG)class javaid(object): def __init__(self,dir): self._function = &#x27;&#x27; self._fpanttern = &#x27;&#x27; self._line = 0 self._dir = dir self._shortfilename = &#x27;&#x27; # 文件名 self._filename = &#x27;&#x27; # 文件路径 self._vultype = &#x27;&#x27; # 漏洞类型 self._code = &#x27;&#x27; # 匹配到的这行代码，文件路径 def _run(self): try: self.banner() self.handlePath(self._dir) print(&quot;[-]【JavaID】identify danger function Finished!&quot; ) except: raise def report_id(self,vul): # print( &quot;[+]【&quot;+vul+&quot;】identify danger function [&quot;+self._function+&quot;] in file [&quot;+self._filename+&quot;]&quot;) print( &quot;[+]【&quot;+self._vultype+&quot;】【&quot;+self._function+&quot;】【&quot;+ self._shortfilename + &quot;】 &quot;+self._filename) # def report_line(self): # print( &quot; --&gt; [+] on line : &quot;+ str(self._line)) def handlePath(self, path): &#x27;&#x27;&#x27; 用递归遍历所有的文件名，并发给handleFile()方法去处理 &#x27;&#x27;&#x27; dirs = os.listdir(path) for d in dirs: subpath = os.path.join(path, d) if os.path.isfile(subpath): if os.path.splitext(subpath)[1] == &#x27;.java&#x27; or os.path.splitext(subpath)[1] == &#x27;.xml&#x27;: self._filename =subpath (_, self._shortfilename) = os.path.split(subpath) self.handleFile(subpath) # logging.info(subpath) # input(&quot;&gt;&gt;&quot;) else: self.handlePath(subpath) def handleFile(self, fileName): &#x27;&#x27;&#x27; 打开文件，经过remove_comment处理后，发给check_regexp去使用正则处理 &#x27;&#x27;&#x27; #print &#x27;begin read file:&#x27; + fileName f = open(fileName, &#x27;r&#x27;) self._line = 0 content = f.read() content=self.remove_comment(content) self.check_regexp(content) f.close() #print &#x27;read over file:&#x27; + fileName #print &#x27;------------------------&#x27; def get_code(self,result): fl = open(self._filename, &#x27;r&#x27;) self._line =0 while 1: line = fl.readline() if not line: break self._line += 1 if result in line: self._code = line.strip() print(&quot;line:&quot;,self._line,&quot; code: \033[1;31m&quot;,self._code,&quot;\033[0m&quot;) break def regexp_search(self,rule_dom,content): &#x27;&#x27;&#x27; 传入rule_dom,content，通过rule_dom来找到对应的规则，每条规则可以对应多个正则 &#x27;&#x27;&#x27; regmatch_dom = rule_dom[0].xpath(&quot;regmatch&quot;) regexp_doms = regmatch_dom[0].xpath(&quot;regexp&quot;) if regmatch_dom != None else [] for regexp_dom in regexp_doms: exp_pattern = re.compile(regexp_dom.text) result = exp_pattern.findall(content) if result: for i in result: # logging.info(&quot;=======result ========&quot;+i) #print( &quot;identify sfunction is : &quot;+self._function) self.report_id(self._vultype) self.get_code(i) # print(&quot;&quot;) # self.function_search_line() return True def check_regexp(self, content): &#x27;&#x27;&#x27; 使用正则搜索文件内容中的关键字 &#x27;&#x27;&#x27; if not content: return self._xmlstr_dom = etree.parse(regexp) javaid_doms = self._xmlstr_dom.xpath(&quot;javaid&quot;) for javaid_dom in javaid_doms: self._vultype =javaid_dom.get(&quot;vultype&quot;) #print( &quot;vul_type &quot;+self._vultype) function_doms = javaid_dom.xpath(&quot;function&quot;) for function_dom in function_doms: rule_dom = function_dom.xpath(&quot;rule&quot;) self._function =rule_dom[0].get(&quot;name&quot;) self.regexp_search(rule_dom,content) #print( &quot;check_regexp search ...&quot;) return True def banner(self): print( &quot;[-]【JavaID】 Danger function identify tool&quot;)if __name__ == &#x27;__main__&#x27;: parser = optparse.OptionParser(&#x27;usage: python %prog [options](eg: python %prog -d /user/java/demo)&#x27;) parser.add_option(&#x27;-d&#x27;, &#x27;--dir&#x27;, dest = &#x27;dir&#x27;, type = &#x27;string&#x27;, help = &#x27;source code file dir&#x27;) (options, args) = parser.parse_args() path = os.path.dirname(__file__) regexp = path+&quot;/regexp.xml&quot; if options.dir == None or options.dir == &quot;&quot;: parser.print_help() sys.exit() dir =options.dir javaidentify = javaid(dir) javaidentify._run()
regexp.xml&lt;root&gt; &lt;javaid vultype=&#x27;XXE&#x27;&gt; &lt;function&gt; &lt;rule name=&#x27;SAXReader&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;new\s+SAXReader\(\)&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;SAXBuilder&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;new\s+SAXBuilder\(\)&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;SAXParser&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;newSAXParser\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;XMLReader&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;createXMLReader\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;DocumentBuilder&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;newDocumentBuilder\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;XMLStreamReader&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;createXMLStreamReader\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;/javaid&gt; &lt;javaid vultype=&#x27;ObjectDeserialization&#x27;&gt; &lt;function&gt; &lt;rule name=&#x27;readObject&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.readObject\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;parseObject&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;JSON\.parseObject\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;readValue&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;ObjectMapper\.readValue&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;fromXML&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;fromXML\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;readUnshared&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;readUnshared\(&lt;/regexp&gt; &lt;/regmatc