t; &lt;regexp&gt;HttpRequest\.post&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;Jsoup&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;Jsoup\.connect&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;RestTemplate&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.getForObject\(&lt;/regexp&gt; &lt;regexp&gt;RestTemplate&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;SimpleDriverDataSource&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.getConnection\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;DriverManager&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.getConnection\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;/javaid&gt; &lt;javaid vultype=&#x27;FileUpload&#x27;&gt; &lt;function&gt; &lt;rule name=&#x27;MultipartFile&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.getOriginalFilename\(|MultipartFile\s&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;/javaid&gt; &lt;javaid vultype=&#x27;File&#x27;&gt; &lt;function&gt; &lt;rule name=&#x27;createNewFile&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.createNewFile\(|FileOutputStream\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;delete&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;\.delete\(\)&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;FileInputStream&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;new\sFileInputStream\(&lt;/regexp&gt; &lt;/regmatch&gt; &lt;/rule&gt; &lt;/function&gt; &lt;function&gt; &lt;rule name=&#x27;maybe&#x27;&gt; &lt;regmatch&gt; &lt;regexp&gt;org\.springframework\.stereotype\.Controller&lt;/regexp&gt; &lt;regexp&gt;org\.apache\.commons\.io\.FileUtils&lt;/regexp&gt; &lt;regexp&gt;import\sjava\.nio\.file\.Files&lt;/regexp&gt; &lt;regexp&gt;import\sjava\.nio\.file\.