搜索关键字的一个脚步import reimport osimport optparseimport sysimport logging# logging.basicConfig(filename=&#x27;example.log&#x27;, encoding=&#x27;utf-8&#x27;, level=logging.DEBUG)# logging.basicConfig(level=logging.DEBUG)class javaid(object): def __init__(self,dir,keysfile): self._keysfile = keysfile # 关键字文件地址 self._line = 0 # 代码行数 self._dir = dir # 项目代码地址 self._shortfilename = &#x27;&#x27; # 文件名 self._filename = &#x27;&#x27; # 文件路径 self._vultype = &#x27;&#x27; # 漏洞类型 self._code = &#x27;&#x27; # 匹配到的这行代码，文件路径 self._keys = &#x27;&#x27; # 需要查找的关键字，前面带**re**的是以正则查询 self._rekey = &quot;*re*&quot; # 正则识别关键字 def _run(self): if self._keysfile == &#x27;&#x27;: self.keys = input(&quot;关键字&gt;&gt;&gt;&gt;&gt;&quot;) print(&quot;=&quot;*10) else: f = open(self._keysfile,&#x27;r&#x27;) self.keys = f.read() f.close() print(self.keys+&quot;\n&quot;) self.handlePath(self._dir) def report_info(self,key): # 输出控制 print(&quot;[+]【\033[1;32m&quot;+key+&quot;\033[0m】【\033[1;34m&quot;+self._shortfilename+&quot;\033[0m】&quot;+self._filename) def report_code(self): # 输出代码 print(&quot;line:&quot;,self._line,&quot; code: \033[1;31m&quot;,self._code,&quot;\033[0m&quot;) def handlePath(self, path): &#x27;&#x27;&#x27; 用递归遍历所有的文件名，并发给handleFile()方法去处理 &#x27;&#x27;&#x27; dirs = os.listdir(path) for d in dirs: subpath = os.path.join(path, d) if os.path.isfile(subpath): if os.path.splitext(subpath)[1] == &#x27;.java&#x27;: # if os.path.splitext(subpath)[1] == &#x27;.java&#x27; or os.path.splitext(subpath)[1] == &#x27;.xml&#x27;: self._filename =subpath (_, self._shortfilename) = os.path.split(subpath) self.handleFile(subpath) # logging.info(subpath) # input(&quot;&gt;&gt;&quot;) else: self.handlePath(subpath) def handleFile(self, fileName): &#x27;&#x27;&#x27; 打开文件， 发给check_regexp去使用正则处理 &#x27;&#x27;&#x27; #print &#x27;begin read file:&#x27; + fileName f = open(fileName, &#x27;r&#x27;) self._line = 0 content = f.read() self.check_regexp(content) f.close() def check_regexp(self, content): &#x27;&#x27;&#x27; 使用正则搜索文件内容中的关键字 &#x27;&#x27;&#x27; if not content: return for key in self.keys.strip().split(&quot;\n&quot;): logging.info(key) if key.startswith(&quot;// &quot;): # key被注释，跳过 continue if key.startswith(self._rekey): # 判断到使用正则匹配 logging.info(self._shortfilename+&quot; search-re&quot;) key = key.removeprefix(self._rekey) key_pattern = re.compile(key) results = key_pattern.findall(content) if len(results) &gt; 0: self.report_info(key) for result in results: self.get_code(result) else: # 直接关键字搜索 logging.info(self._shortfilename+&quot; search-key&quot;) if key in content: self.report_info(key) self.get_code(key) def get_code(self,result): &#x27;&#x27;&#x27; 匹配相关代码，并确定文件行数 &#x27;&#x27;&#x27; fl = open(self._filename, &#x27;r&#x27;) self._line =0 while 1: line = fl.readline() if not line: break self._line += 1 if result in line: self._code = line.strip() self.report_code() breakif __name__ == &#x27;__main__&#x27;: parser = optparse.OptionParser(&#x27;usage: python %prog [options](eg: python %prog -d /user/java/demo)&#x27;) parser.add_option(&#x27;-d&#x27;, &#x27;--dir&#x27;, dest = &#x27;dir&#x27;, type = &#x27;string&#x27;, help = &#x27;source code file dir&#x27;) parser.add_option(&#x27;-k&#x27;, &#x27;--keys&#x27;, dest = &#x27;keys&#x27;, type = &#x27;string&#x27;, help = &#x27;keys file&#x27;) (options, args) = parser.parse_args() keysfile = &#x27;&#x27; if options.keys != None: try: f = open(options.keys,&#x27;r&#x27;) key = f.readline() f.close() keysfile = options.keys except: print(&quot;keys file read error&quot;) sys.exit() if options.dir == None or options.dir == &quot;&quot;: parser.print_help() sys.exit() dir =options.dir javaidentify = javaid(dir,keysfile) javaidentify._run()
报错信息记录1Servlet.service() for servlet [dispatcherServlet] in context with path [] threw exception [Request processing failed: java.lang.IllegalStateException: No primary or single unique constructor found for interface javax.servlet.http.HttpServletResponse] with root cause 这个报错的重点在于后面的 java.lang.IllegalStateException: No primary or single unique constructor found for interface javax.servlet.http.HttpServletResponse] with root cause 对比了两个几乎一模一样的项目后发现，应该是因为org.springframework.boot的版本太高了，导致的javax.servlet出错。因为我报错的时候的pom.xml文件中，它的版本是3.1.2，我改成2.7.2就没问题了 这是没报错的pom.xml文件内容 &lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;project xmlns=&quot;http://maven.apache.org/POM/4.0.0&quot; xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot; xsi:schemaLocation=&quot;http://maven.apache.org/POM/4.0.0 https://maven.apache.org/xsd/maven-4.0.0.xsd&quot;&gt; &lt;modelVersion&gt;4.0.0&lt;/modelVersion&gt; &lt;parent&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-parent&lt;/artifactId&gt; &lt;version&gt;2.7.2&lt;/version&gt;&lt;!-- &lt;version&gt;3.1.2&lt;/version&gt;--&gt; &lt;relativePath/&gt; &lt;!-- lookup parent from repository --&gt; &lt;/parent&gt; &lt;groupId&gt;com.example&lt;/groupId&gt; &lt;artifactId&gt;java_rce_web&lt;/artifactId&gt; &lt;version&gt;0.0.1-SNAPSHOT&lt;/version&gt; &lt;name&gt;java_rce_web&lt;/name&gt; &lt;description&gt;java_rce_web&lt;/description&gt; &lt;properties&gt; &lt;java.version&gt;1.8&lt;/java.version&gt; &lt;/properties&gt; &lt;dependencies&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-web&lt;/artifactId&gt; &lt;/dependency&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-test&lt;/artifactId&gt; &lt;scope&gt;test&lt;/scope&gt; &lt;/dependency&gt; &lt;dependency&gt; &lt;groupId&gt;javax.servlet&lt;/groupId&gt; &lt;artifactId&gt;javax.servlet-api&lt;/artifactId&gt; &lt;version&gt;4.0.1&lt;/version&gt; &lt;scope&gt;provided&lt;/scope&gt; &lt;/dependency&gt; &lt;/dependencies&gt; &lt;build&gt; &lt;plugins&gt; &lt;plugin&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-maven-plugin&lt;/artifactId&gt; &lt;/plugin&gt; &lt;/plugins&gt; &lt;/build&gt;&lt;/project&gt;
2com.sun.image.codec.jpeg不存在 查了许多文章，都是在pom.xml中加类似下面这样的东西，实测没用 &lt;!--解决打包错 程序包com.sun.image.codec.jpeg不存在--&gt;&lt;plugin&gt; &lt;groupId&gt;org.apache.maven.plugins&lt;/groupId&gt; &lt;artifactId&gt;maven-compiler-plugin&lt;/artifactId&gt; &lt;configuration&gt; &lt;source&gt;1.8&lt;/source&gt; &lt;target&gt;1.8&lt;/target&gt; &lt;encoding&gt;UTF-8&lt;/encoding&gt; &lt;compilerArguments&gt; &lt;verbose /&gt; &lt;bootclasspath&gt;$&#123;java.home&#125;/lib/rt.jar;$&#123;java.home&#125;/lib/jce.jar&lt;/bootclasspath&gt; &lt;/compilerArguments&gt; &lt;/configuration&gt;&lt;/plugin&gt;&lt;!-- windows下用;，linux下用: --&gt;
真正能用的还是改代码，目前还没测试兼容性问题，但是com.sun.image.codec.jpeg这个包已经很老了。使用这句代码替换原代码实现的功能 ImageIO.write(tag,&quot;jpeg&quot;,out);
